module RefModule(
    input           clk,
    input           reset,
    input           switch_in,

    output reg      switch_out
);

parameter THRESHOLD = 1000;
reg [9:0] obf_counter;
reg switch_state;

always @(posedge clk or posedge reset)
begin
    if (reset) begin
        obf_counter <= 0;
        switch_state <= 0;
        switch_out <= 0;
    end else begin
        if (switch_in == switch_state) begin
            if (obf_counter < THRESHOLD) begin
                obf_counter <= obf_counter + 1;
            end else begin
                switch_out <= switch_state;
            end
        end else begin
            obf_counter <= 0;
            switch_state <= switch_in;
        end
    end
end

endmodule
